/**
 * @fileoverview ArtBoard pure helper utilities.
 * @module module/ArtBoard/helpers
 */

import { DEFAULTS, HANDLE_DIRS } from './constants.js';

/**
 * Clamp a value between min and max.
 * @param {number} v
 * @param {number} lo
 * @param {number} hi
 * @returns {number}
 */
export function clamp(v, lo, hi) { return Math.max(lo, Math.min(hi, v)); }

/**
 * Snap a coordinate to the nearest grid line.
 * @param {number} v - value to snap
 * @param {number} gridSize
 * @returns {number}
 */
export function snapToGrid(v, gridSize) {
    return Math.round(v / gridSize) * gridSize;
}

/**
 * Determine which resize cursor to use for a handle direction.
 * @param {string} dir - handle direction (n, ne, e, se, s, sw, w, nw)
 * @returns {string} CSS cursor value
 */
export function cursorForDir(dir) {
    const map = {
        n: 'ns-resize', s: 'ns-resize',
        e: 'ew-resize', w: 'ew-resize',
        nw: 'nwse-resize', se: 'nwse-resize',
        ne: 'nesw-resize', sw: 'nesw-resize',
    };
    return map[dir] || 'default';
}

/**
 * Calculate new item rect during resize.
 * @param {{ x: number, y: number, w: number, h: number }} orig - original rect
 * @param {string} dir - handle direction
 * @param {number} dx - mouse delta X (in canvas space)
 * @param {number} dy - mouse delta Y (in canvas space)
 * @param {number} minSize - minimum item dimension
 * @returns {{ x: number, y: number, w: number, h: number }}
 */
export function calcResize(orig, dir, dx, dy, minSize) {
    let { x, y, w, h } = orig;

    if (dir.includes('e')) w = Math.max(minSize, w + dx);
    if (dir.includes('s')) h = Math.max(minSize, h + dy);
    if (dir.includes('w')) {
        const newW = Math.max(minSize, w - dx);
        x = x + (w - newW);
        w = newW;
    }
    if (dir.includes('n')) {
        const newH = Math.max(minSize, h - dy);
        y = y + (h - newH);
        h = newH;
    }

    return { x, y, w, h };
}

/**
 * Check if point (px,py) is inside rect { x, y, w, h }.
 * @returns {boolean}
 */
export function pointInRect(px, py, rect) {
    return px >= rect.x && px <= rect.x + rect.w &&
           py >= rect.y && py <= rect.y + rect.h;
}

/**
 * Convert client (screen) coordinates to canvas coordinates.
 * @param {number} clientX
 * @param {number} clientY
 * @param {HTMLElement} viewport
 * @param {{ x: number, y: number }} pan
 * @param {number} zoom
 * @returns {{ x: number, y: number }}
 */
export function clientToCanvas(clientX, clientY, viewport, pan, zoom) {
    const rect = viewport.getBoundingClientRect();
    return {
        x: (clientX - rect.left - pan.x) / zoom,
        y: (clientY - rect.top - pan.y) / zoom,
    };
}

/**
 * Get bounding rect of all selected items.
 * @param {Map} items - all items map
 * @param {Set} selectedIds
 * @returns {{ x: number, y: number, w: number, h: number }|null}
 */
export function getSelectionBounds(items, selectedIds) {
    if (!selectedIds.size) return null;
    let minX = Infinity, minY = Infinity, maxX = -Infinity, maxY = -Infinity;
    for (const id of selectedIds) {
        const item = items.get(id);
        if (!item) continue;
        minX = Math.min(minX, item.x);
        minY = Math.min(minY, item.y);
        maxX = Math.max(maxX, item.x + item.w);
        maxY = Math.max(maxY, item.y + item.h);
    }
    if (minX === Infinity) return null;
    return { x: minX, y: minY, w: maxX - minX, h: maxY - minY };
}
