/**
 * @fileoverview ArtBoard centralised event binding with AbortController.
 *
 * Handles: item click/drag, resize handles, canvas pan/zoom,
 * keyboard shortcuts, toolbar clicks, context menu, file drop.
 *
 * @module module/ArtBoard/events
 */

import razyui from '../../index.js';
import { CLS, SEL, DEFAULTS, ITEM_TYPE } from './constants.js';
import { clientToCanvas, calcResize, clamp, snapToGrid } from './helpers.js';
import {
    selectItem, deselectAll, selectAll, deleteSelected,
    pushUndo, undo, redo, nextZ,
} from './state.js';
import {
    syncItemElement,
    markSelected, clearSelection, updateCanvasTransform,
    updateZoomDisplay,
} from './view.js';

/**
 * Bind all board events.
 *
 * @param {object} ctx - { board, viewport, canvas, toolbar, zoomInfo, state, config,
 *                         getPan, setPan, getZoom, setZoom, addItemInternal,
 *                         onContextMenu, onSelectionChange, onItemChange }
 * @param {AbortSignal} signal
 */
export function bindEvents(ctx, signal) {
    const sigOpts = { signal };

    // ── Item mousedown (select + start drag) ──
    ctx.canvas.on('mousedown', function (e) {
        if (e.button !== 0) return;
        const itemEl = this;
        handleItemMousedown(e, itemEl, ctx, signal);
    }, { selector: SEL.ITEM, signal });

    ctx.canvas.on('touchstart', function (e) {
        const itemEl = this;
        handleItemMousedown(e, itemEl, ctx, signal);
    }, { selector: SEL.ITEM, signal, passive: false });

    // ── Handle mousedown (resize) ──
    ctx.canvas.on('mousedown', function (e) {
        if (e.button !== 0) return;
        e.stopPropagation();
        handleResizeStart(e, this, ctx, signal);
    }, { selector: SEL.HANDLE, signal });

    ctx.canvas.on('touchstart', function (e) {
        e.stopPropagation();
        handleResizeStart(e, this, ctx, signal);
    }, { selector: SEL.HANDLE, signal, passive: false });

    // ── Canvas click (deselect) ──
    ctx.viewport.on('mousedown', function (e) {
        if (e.target === ctx.canvas[0] || e.target === ctx.viewport[0]) {
            if (e.button === 0) {
                deselectAll(ctx.state);
                clearSelection(ctx.canvas);
                ctx.onSelectionChange?.();
            }
            if (e.button === 1 || (e.button === 0 && e.altKey)) {
                // Middle-click or Alt+click → start panning
                e.preventDefault();
                startPan(e, ctx, signal);
            }
        }
    }, sigOpts);

    // ── Wheel zoom ──
    ctx.viewport.on('wheel', function (e) {
        e.preventDefault();
        const delta = e.deltaY > 0 ? -DEFAULTS.zoomStep : DEFAULTS.zoomStep;
        const newZoom = clamp(ctx.getZoom() + delta, DEFAULTS.minZoom, DEFAULTS.maxZoom);
        ctx.setZoom(newZoom);
        updateCanvasTransform(ctx.canvas, ctx.getPan(), newZoom);
        updateZoomDisplay(ctx.zoomInfo, newZoom);
    }, { signal, passive: false });

    // ── Right-click on items ──
    ctx.canvas.on('contextmenu', function (e) {
        e.preventDefault();
        e.stopPropagation();
        const itemId = this.getAttribute('data-item-id');
        // Ensure item is selected
        if (!ctx.state.selected.has(itemId)) {
            deselectAll(ctx.state);
            clearSelection(ctx.canvas);
            selectItem(ctx.state, itemId, false);
            markSelected(ctx.canvas, itemId);
            ctx.onSelectionChange?.();
        }
        ctx.onContextMenu?.(e, itemId);
    }, { selector: SEL.ITEM, signal });

    // ── Right-click on canvas (board-level context menu) ──
    ctx.viewport.on('contextmenu', function (e) {
        if (e.target === ctx.canvas[0] || e.target === ctx.viewport[0]) {
            e.preventDefault();
            ctx.onContextMenu?.(e, null);
        }
    }, sigOpts);

    // ── Toolbar buttons ──
    ctx.toolbar.on('click', function (e) {
        const action = this.getAttribute('data-action');
        handleToolbarAction(action, ctx);
    }, { selector: '.' + CLS.TOOLBAR_BTN, signal });

    // ── Keyboard shortcuts ──
    razyui(document).on('keydown', function (e) {
        if (!ctx.board[0].contains(document.activeElement) &&
            document.activeElement !== document.body) return;

        const key = e.key.toLowerCase();
        const ctrl = e.ctrlKey || e.metaKey;

        if (key === 'delete' || key === 'backspace') {
            e.preventDefault();
            pushUndo(ctx.state);
            const deleted = deleteSelected(ctx.state);
            for (const id of deleted) {
                ctx.canvas.find(`[data-item-id="${id}"]`).each(function () { this.remove(); });
            }
            ctx.onSelectionChange?.();
        }
        if (ctrl && key === 'a') {
            e.preventDefault();
            selectAll(ctx.state);
            clearSelection(ctx.canvas);
            for (const id of ctx.state.selected) markSelected(ctx.canvas, id);
            ctx.onSelectionChange?.();
        }
        if (ctrl && key === 'z' && !e.shiftKey) {
            e.preventDefault();
            if (undo(ctx.state)) ctx.rebuildCanvas?.();
        }
        if (ctrl && (key === 'y' || (key === 'z' && e.shiftKey))) {
            e.preventDefault();
            if (redo(ctx.state)) ctx.rebuildCanvas?.();
        }
    }, sigOpts);

    // ── File drop ──
    ctx.viewport.on('dragover', function (e) {
        e.preventDefault();
        e.dataTransfer.dropEffect = 'copy';
    }, sigOpts);

    ctx.viewport.on('drop', function (e) {
        e.preventDefault();
        handleFileDrop(e, ctx);
    }, sigOpts);
}

// ── Item drag ──

function handleItemMousedown(e, itemEl, ctx, signal) {
    const itemId = itemEl.getAttribute('data-item-id');
    const item = ctx.state.items.get(itemId);
    if (!item || item.locked) return;

    e.stopPropagation();

    // Select
    const additive = e.shiftKey || e.ctrlKey || e.metaKey;
    if (!ctx.state.selected.has(itemId)) {
        if (!additive) {
            deselectAll(ctx.state);
            clearSelection(ctx.canvas);
        }
        selectItem(ctx.state, itemId, additive);
        markSelected(ctx.canvas, itemId);
        ctx.onSelectionChange?.();
    }

    // Bring to front
    item.z = nextZ(ctx.state);
    razyui(itemEl).css('z-index', item.z);

    // Drag setup
    const startPt = getEventPoint(e);
    const startPositions = new Map();
    for (const selId of ctx.state.selected) {
        const d = ctx.state.items.get(selId);
        if (d) startPositions.set(selId, { x: d.x, y: d.y });
    }

    pushUndo(ctx.state);
    let moved = false;

    const onMove = (ev) => {
        const pt = getEventPoint(ev);
        const dx = (pt.x - startPt.x) / ctx.getZoom();
        const dy = (pt.y - startPt.y) / ctx.getZoom();

        for (const [selId, startPos] of startPositions) {
            const d = ctx.state.items.get(selId);
            if (!d) continue;
            let nx = startPos.x + dx;
            let ny = startPos.y + dy;
            if (ctx.config.snap) {
                nx = snapToGrid(nx, ctx.config.gridSize || DEFAULTS.gridSize);
                ny = snapToGrid(ny, ctx.config.gridSize || DEFAULTS.gridSize);
            }
            d.x = nx;
            d.y = ny;
            const el = ctx.canvas.find(`[data-item-id="${selId}"]`);
            syncItemElement(el[0], d);
        }
        moved = true;
    };

    const onUp = () => {
        document.removeEventListener('mousemove', onMove);
        document.removeEventListener('mouseup', onUp);
        document.removeEventListener('touchmove', onMove);
        document.removeEventListener('touchend', onUp);
        if (moved) ctx.onItemChange?.();
    };

    document.addEventListener('mousemove', onMove, { signal });
    document.addEventListener('mouseup', onUp, { signal });
    document.addEventListener('touchmove', onMove, { signal, passive: false });
    document.addEventListener('touchend', onUp, { signal });
}

// ── Resize ──

function handleResizeStart(e, handleEl, ctx, signal) {
    const dir = handleEl.getAttribute('data-dir');
    const itemEl = handleEl.closest(SEL.ITEM);
    if (!itemEl) return;
    const itemId = itemEl.getAttribute('data-item-id');
    const item = ctx.state.items.get(itemId);
    if (!item || item.locked) return;

    const startPt = getEventPoint(e);
    const orig = { x: item.x, y: item.y, w: item.w, h: item.h };
    pushUndo(ctx.state);

    const onMove = (ev) => {
        const pt = getEventPoint(ev);
        const dx = (pt.x - startPt.x) / ctx.getZoom();
        const dy = (pt.y - startPt.y) / ctx.getZoom();
        const newRect = calcResize(orig, dir, dx, dy, DEFAULTS.minItemSize);

        if (ctx.config.snap) {
            newRect.x = snapToGrid(newRect.x, ctx.config.gridSize || DEFAULTS.gridSize);
            newRect.y = snapToGrid(newRect.y, ctx.config.gridSize || DEFAULTS.gridSize);
            newRect.w = snapToGrid(newRect.w, ctx.config.gridSize || DEFAULTS.gridSize) || DEFAULTS.minItemSize;
            newRect.h = snapToGrid(newRect.h, ctx.config.gridSize || DEFAULTS.gridSize) || DEFAULTS.minItemSize;
        }

        Object.assign(item, newRect);
        syncItemElement(itemEl, item);
    };

    const onUp = () => {
        document.removeEventListener('mousemove', onMove);
        document.removeEventListener('mouseup', onUp);
        document.removeEventListener('touchmove', onMove);
        document.removeEventListener('touchend', onUp);
        ctx.onItemChange?.();
    };

    document.addEventListener('mousemove', onMove, { signal });
    document.addEventListener('mouseup', onUp, { signal });
    document.addEventListener('touchmove', onMove, { signal, passive: false });
    document.addEventListener('touchend', onUp, { signal });
}

// ── Panning ──

function startPan(e, ctx, signal) {
    const startPt = getEventPoint(e);
    const startPan = { ...ctx.getPan() };

    const onMove = (ev) => {
        const pt = getEventPoint(ev);
        ctx.setPan({
            x: startPan.x + (pt.x - startPt.x),
            y: startPan.y + (pt.y - startPt.y),
        });
        updateCanvasTransform(ctx.canvas, ctx.getPan(), ctx.getZoom());
    };

    const onUp = () => {
        document.removeEventListener('mousemove', onMove);
        document.removeEventListener('mouseup', onUp);
    };

    document.addEventListener('mousemove', onMove, { signal });
    document.addEventListener('mouseup', onUp, { signal });
}

// ── Toolbar actions ──

function handleToolbarAction(action, ctx) {
    switch (action) {
        case 'zoom-in': {
            const z = clamp(ctx.getZoom() + DEFAULTS.zoomStep, DEFAULTS.minZoom, DEFAULTS.maxZoom);
            ctx.setZoom(z);
            updateCanvasTransform(ctx.canvas, ctx.getPan(), z);
            updateZoomDisplay(ctx.zoomInfo, z);
            break;
        }
        case 'zoom-out': {
            const z = clamp(ctx.getZoom() - DEFAULTS.zoomStep, DEFAULTS.minZoom, DEFAULTS.maxZoom);
            ctx.setZoom(z);
            updateCanvasTransform(ctx.canvas, ctx.getPan(), z);
            updateZoomDisplay(ctx.zoomInfo, z);
            break;
        }
        case 'zoom-reset':
            ctx.setZoom(1);
            ctx.setPan({ x: 0, y: 0 });
            updateCanvasTransform(ctx.canvas, ctx.getPan(), 1);
            updateZoomDisplay(ctx.zoomInfo, 1);
            break;
        case 'fit':
            fitToScreen(ctx);
            break;
        case 'grid':
            ctx.board.toggleClass(CLS.GRID_VISIBLE);
            break;
        case 'select-all':
            selectAll(ctx.state);
            clearSelection(ctx.canvas);
            for (const id of ctx.state.selected) markSelected(ctx.canvas, id);
            ctx.onSelectionChange?.();
            break;
        case 'delete': {
            pushUndo(ctx.state);
            const deleted = deleteSelected(ctx.state);
            for (const id of deleted) {
                ctx.canvas.find(`[data-item-id="${id}"]`).each(function () { this.remove(); });
            }
            ctx.onSelectionChange?.();
            break;
        }
    }
}

// ── Fit to screen ──

function fitToScreen(ctx) {
    if (!ctx.state.items.size) return;
    let minX = Infinity, minY = Infinity, maxX = -Infinity, maxY = -Infinity;
    for (const item of ctx.state.items.values()) {
        minX = Math.min(minX, item.x);
        minY = Math.min(minY, item.y);
        maxX = Math.max(maxX, item.x + item.w);
        maxY = Math.max(maxY, item.y + item.h);
    }

    const cw = maxX - minX;
    const ch = maxY - minY;
    if (cw <= 0 || ch <= 0) return;

    const vr = ctx.viewport[0].getBoundingClientRect();
    const pad = 40;
    const zoom = Math.min((vr.width - pad * 2) / cw, (vr.height - pad * 2) / ch, DEFAULTS.maxZoom);

    ctx.setZoom(zoom);
    ctx.setPan({
        x: (vr.width - cw * zoom) / 2 - minX * zoom,
        y: (vr.height - ch * zoom) / 2 - minY * zoom,
    });
    updateCanvasTransform(ctx.canvas, ctx.getPan(), zoom);
    updateZoomDisplay(ctx.zoomInfo, zoom);
}

// ── File drop handler ──

function handleFileDrop(e, ctx) {
    const files = e.dataTransfer?.files;
    if (!files?.length) return;

    const dropPt = clientToCanvas(
        e.clientX, e.clientY,
        ctx.viewport[0], ctx.getPan(), ctx.getZoom()
    );

    let offsetX = 0;
    for (const file of files) {
        const isImage = file.type.startsWith('image/');
        const isVideo = file.type.startsWith('video/');
        if (!isImage && !isVideo) continue;

        const url = URL.createObjectURL(file);
        ctx.addItemInternal({
            type: isImage ? ITEM_TYPE.IMAGE : ITEM_TYPE.VIDEO,
            src: url,
            x: dropPt.x + offsetX,
            y: dropPt.y,
            w: 300,
            h: 200,
            label: file.name,
        });
        offsetX += 320;
    }
}

// ── Helpers ──

function getEventPoint(e) {
    if (e.touches?.length) return { x: e.touches[0].clientX, y: e.touches[0].clientY };
    return { x: e.clientX, y: e.clientY };
}
